#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;
int n, m, ans = 0;
vector<int> e[N];
int in[N], topo[N];

bool toposort()
{
	int t = 0;
	priority_queue<int> q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i);
	while(!q.empty())
	{
		int u = q.top();
		q.pop();
		topo[++t] = u;
		for(int v : e[u])
		{
			in[v]--;
			if(!in[v]) q.push(v);
		}
	}
	return t == n;
}

int main()
{
	int t;
	cin >> t;
	while(t--)
	{
		cin >> n >> m;
		for(int i = 1; i <= n; i++)
			e[i].clear(), in[i] = 0;
		for(int i = 1; i <= m; i++)
		{
			int u, v;
			cin >> u >> v;
			e[v].push_back(u);
			in[u]++;
		}
		if(!toposort())
		{
			cout << "Impossible!\n";
			continue;
		}
		for(int i = n; i >= 1; i--)
			cout << topo[i] << ' ';
		cout << endl;
	}
	return 0;	
}
